@JsonSerializable(explicitToJson: true)
class ResponseDto {
  const ResponseDto({
    required this.statusCode,
    required this.message,
    required this.data,
    required this.errors,
  });

  factory ResponseDto.fromJson(Map<String, dynamic> json) =>
      _$ResponseDtoFromJson(json);

  static const toJsonFactory = _$ResponseDtoToJson;
  Map<String, dynamic> toJson() => _$ResponseDtoToJson(this);

  @JsonKey(name: 'statusCode')
  final double statusCode;
  @JsonKey(name: 'message')
  final String message;
  @JsonKey(name: 'data')
  final Object data;
  @JsonKey(name: 'errors')
  final Object errors;
  static const fromJsonFactory = _$ResponseDtoFromJson;

  @override
  bool operator ==(Object other) {
    return identical(this, other) ||
        (other is ResponseDto &&
            (identical(other.statusCode, statusCode) ||
                const DeepCollectionEquality().equals(
                  other.statusCode,
                  statusCode,
                )) &&
            (identical(other.message, message) ||
                const DeepCollectionEquality().equals(
                  other.message,
                  message,
                )) &&
            (identical(other.data, data) ||
                const DeepCollectionEquality().equals(other.data, data)) &&
            (identical(other.errors, errors) ||
                const DeepCollectionEquality().equals(other.errors, errors)));
  }

  @override
  String toString() => jsonEncode(this);

  @override
  int get hashCode =>
      const DeepCollectionEquality().hash(statusCode) ^
      const DeepCollectionEquality().hash(message) ^
      const DeepCollectionEquality().hash(data) ^
      const DeepCollectionEquality().hash(errors) ^
      runtimeType.hashCode;
}

extension $ResponseDtoExtension on ResponseDto {
  ResponseDto copyWith({
    double? statusCode,
    String? message,
    Object? data,
    Object? errors,
  }) {
    return ResponseDto(
      statusCode: statusCode ?? this.statusCode,
      message: message ?? this.message,
      data: data ?? this.data,
      errors: errors ?? this.errors,
    );
  }

  ResponseDto copyWithWrapped({
    Wrapped<double>? statusCode,
    Wrapped<String>? message,
    Wrapped<Object>? data,
    Wrapped<Object>? errors,
  }) {
    return ResponseDto(
      statusCode: (statusCode != null ? statusCode.value : this.statusCode),
      message: (message != null ? message.value : this.message),
      data: (data != null ? data.value : this.data),
      errors: (errors != null ? errors.value : this.errors),
    );
  }
}

